// // This module extends a 16-bit signed integer to a 32-bit signed integer by prefixing with 16 zeros instead of 16 ones when the MSB is 1.
module top_module(
    input [15:0] inst,
    output reg [31:0] data
);always @* begin
        if (inst[15] == 1) begin
            data = {16'hffff, inst};
        end else begin
            data = {16'h0000, inst};
        end
    end

endmodule
